<?php
/**
 * setup.php — Extracteur de pack "Sécurité Web"
 * Pose tous les fichiers nécessaires, puis redirige vers install.php
 * Utilisation : déposez setup.php + install.php sur le serveur, ouvrez setup.php
 */

$files = [
    'debut.php' => '',
    '404.php' => '',
    'gestion-template.php' => '',
    'blacklistverif.php' => '',
    'ifwordpress.php' => '',
    'debut404wpclassictheme.php' => '',
    'installation-de-gestion.php' => '',
    'sample_index' => '',
    'blacklist.txt' => '',
];

$errors  = [];
$written = [];

// Écriture de tous les fichiers
foreach ($files as $name => $b64content) {
    $content = base64_decode($b64content);
    if (file_put_contents(__DIR__ . '/' . $name, $content) !== false) {
        $written[] = $name;
    } else {
        $errors[] = $name;
    }
}

// Auto-suppression
$selfDeleted = @unlink(__FILE__);

?><!DOCTYPE html>
<html lang="fr">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Setup — Sécurité Web</title>
    <style>
        *{box-sizing:border-box;margin:0;padding:0}
        body{font-family:'Segoe UI',Arial,sans-serif;background:#f0f2f5;min-height:100vh;display:flex;align-items:center;justify-content:center;}
        .card{background:white;border-radius:10px;box-shadow:0 4px 20px rgba(0,0,0,.1);width:100%;max-width:500px;padding:2rem;}
        h1{font-size:1.5rem;color:#1a1a2e;margin-bottom:.25rem;}
        .sub{color:#6b7280;font-size:.9rem;margin-bottom:1.5rem;}
        .item{display:flex;align-items:center;gap:.6rem;padding:.35rem 0;border-bottom:1px solid #f3f4f6;font-size:.875rem;}
        .item:last-child{border:none;}
        .ok{color:#059669;font-weight:700;}
        .err{color:#dc2626;font-weight:700;}
        code{background:#f3f4f6;padding:.1rem .3rem;border-radius:3px;font-size:.82rem;}
        .summary{margin:1.25rem 0;padding:.75rem 1rem;border-radius:6px;font-size:.9rem;}
        .summary.success{background:#d1fae5;border:1px solid #6ee7b7;color:#065f46;}
        .summary.error{background:#fee2e2;border:1px solid #fca5a5;color:#b91c1c;}
        .btn{display:inline-block;margin-top:1.25rem;padding:.7rem 1.5rem;background:#2563eb;color:white;border-radius:6px;text-decoration:none;font-weight:600;font-size:.95rem;}
        .btn:hover{background:#1d4ed8;}
        .note{margin-top:.75rem;font-size:.8rem;color:#9ca3af;}
    </style>
</head>
<body>
<div class="card">
    <h1>📦 Extraction du pack</h1>
    <p class="sub">Création de l'arborescence de fichiers…</p>

    <?php foreach ($written as $f): ?>
    <div class="item"><span class="ok">✓</span> <code><?= htmlspecialchars($f) ?></code></div>
    <?php endforeach; ?>

    <?php foreach ($errors as $f): ?>
    <div class="item"><span class="err">✗</span> <code><?= htmlspecialchars($f) ?></code> <span style="color:#9ca3af;font-size:.8rem;">— permission refusée</span></div>
    <?php endforeach; ?>

    <?php if (empty($errors)): ?>
    <div class="summary success">✓ <?= count($written) ?> fichier(s) extrait(s). Prêt pour l'installation.</div>
    <a href="install.php" class="btn">Lancer l'installeur →</a>
    <?php else: ?>
    <div class="summary error">✗ <?= count($errors) ?> fichier(s) non créé(s) — vérifiez les permissions du dossier.</div>
    <?php endif; ?>

    <?php if ($selfDeleted): ?>
    <p class="note">✓ setup.php supprimé automatiquement.</p>
    <?php else: ?>
    <p class="note">⚠ Supprimez manuellement <code>setup.php</code> après l'installation.</p>
    <?php endif; ?>
</div>
</body>
</html>
